+/**
+ * Core notification types and interfaces.
+ *
+ * These types define the shape of notifications throughout the system.
+ * All notification adapters and services work with these types.
+ */
+
+/**
+ * Supported notification channels. Each channel corresponds to
+ * a NotificationAdapter implementation.
+ */
+export type NotificationChannel = 'email' | 'sms' | 'in-app' | 'webhook';
+
+/**
+ * Notification priority levels.
+ */
+export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';
+
+/**
+ * The type of notification, indicating what triggered it.
+ */
+export type NotificationType =
+  | 'order-confirmation'
+  | 'order-status-update'
+  | 'user-welcome'
+  | 'user-profile-update';
+
+/**
+ * The payload sent to a notification adapter for delivery.
+ */
+export interface NotificationPayload {
+  recipient: string;
+  subject: string;
+  body: string;
+  channel: NotificationChannel;
+  priority: NotificationPriority;
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * A notification record after it has been processed.
+ */
+export interface Notification {
+  id: string;
+  type: NotificationType;
+  channel: NotificationChannel;
+  recipient: string;
+  subject: string;
+  body: string;
+  priority: NotificationPriority;
+  status: 'pending' | 'sent' | 'failed';
+  sentAt: Date;
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * Result returned by a NotificationAdapter after attempting delivery.
+ */
+export interface NotificationResult {
+  success: boolean;
+  notificationId: string;
+  channel: NotificationChannel;
+  error?: string;
+}

