/**
 * Core notification types and interfaces.
 *
 * These types define the shape of notifications throughout the system.
 * All notification adapters and services work with these types.
 */

/**
 * Supported notification channels. Each channel corresponds to
 * a NotificationAdapter implementation.
 */
export type NotificationChannel = 'email' | 'sms' | 'in-app' | 'webhook';

/**
 * Notification priority levels.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The type of notification, indicating what triggered it.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'user-welcome'
  | 'user-profile-update';

/**
 * The payload sent to a notification adapter for delivery.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: NotificationPriority;
  metadata?: Record<string, unknown>;
}

/**
 * A notification record after it has been processed.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
  status: 'pending' | 'sent' | 'failed';
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by a NotificationAdapter after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  notificationId: string;
  channel: NotificationChannel;
  error?: string;
}

/**
 * NotificationAdapter interface — the contract all notification channel
 * adapters must implement.
 *
 * CONSTRAINT: Every notification channel (email, SMS, webhook, in-app)
 * must implement this interface and be registered with the NotificationService.
 * Adapters are responsible for the actual delivery mechanism; the
 * NotificationService handles routing and lifecycle.
 */

import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';

export interface NotificationAdapter {
  /**
   * The channel this adapter handles.
   */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Returns a result indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Currently a stub that logs sends in-memory. Replace the send()
 * implementation with a real email provider (SendGrid, SES, etc.)
 * when ready — the interface stays the same.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  from: string;
  replyTo?: string;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ payload: NotificationPayload; timestamp: Date }> = [];

  constructor(private config: EmailConfig) {}

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: "${payload.subject}" from ${this.config.from}`,
    );

    // Stub: store in memory instead of sending a real email
    this.sentEmails.push({ payload, timestamp: new Date() });

    return {
      success: true,
      notificationId: `email-${Date.now()}`,
      channel: 'email',
    };
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): Array<{ payload: NotificationPayload; timestamp: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Architecture: Event-driven via EventBus.
 *
 * The NotificationService subscribes to domain events (order:created,
 * order:status-changed, user:created, etc.) and routes notifications
 * through registered NotificationAdapter implementations.
 *
 * CONSTRAINTS:
 * - All notifications are triggered by EventBus events — no direct calls
 *   from other services.
 * - All delivery goes through adapters implementing NotificationAdapter.
 * - New channels are added by implementing NotificationAdapter and
 *   registering the adapter via registerAdapter().
 * - New event types are handled by adding a subscriber in registerHandlers().
 *
 * Depends on:
 * - EventBus (event system) for receiving all events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for a given channel.
   * Only one adapter per channel is allowed; later registrations
   * replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events that should trigger notifications.
   * All event handling goes through EventBus — no other patterns.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification('order-confirmation', {
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
      priority: 'normal',
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.sendNotification('order-status-update', {
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
      priority: event.newStatus === 'cancelled' ? 'high' : 'normal',
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.sendNotification('user-welcome', {
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro!`,
      channel: 'email',
      priority: 'normal',
      metadata: { userId: event.user.id },
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   * Falls back to in-memory storage if no adapter is registered
   * for the channel.
   */
  private async sendNotification(
    type: NotificationType,
    payload: NotificationPayload,
  ): Promise<NotificationResult | undefined> {
    const id = generateNotificationId();

    const notification: Notification = {
      id,
      type,
      channel: payload.channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      status: 'pending',
      sentAt: new Date(),
      metadata: payload.metadata,
    };

    const adapter = this.adapters.get(payload.channel);
    if (adapter) {
      try {
        const result = await adapter.send(payload);
        notification.status = result.success ? 'sent' : 'failed';
        this.notifications.push(notification);
        this.logger.info(`Notification ${id} ${notification.status} via ${payload.channel}`);
        return result;
      } catch (error) {
        notification.status = 'failed';
        this.notifications.push(notification);
        this.logger.error(`Notification ${id} failed: ${error}`);
        return { success: false, notificationId: id, channel: payload.channel, error: String(error) };
      }
    }

    // No adapter registered — store as sent (in-memory fallback)
    notification.status = 'sent';
    this.notifications.push(notification);
    this.logger.info(`Notification sent: ${id} to ${payload.recipient} (no adapter, in-memory)`);
    return undefined;
  }

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

